-- Example: create a simple table
CREATE TABLE student (
  id INTEGER PRIMARY KEY,
  name TEXT NOT NULL
);

CREATE TABLE enroll (
  sid INTEGER REFERENCES student(id),
  cid INTEGER,
  PRIMARY KEY (sid, cid)
);

CREATE TABLE dept (
  id INTEGER PRIMARY KEY,
  name TEXT
);
CREATE TABLE emp (
  id INTEGER PRIMARY KEY,
  name TEXT,
  dept_id INTEGER REFERENCES dept(id)
);

